import fs from 'fs';
import path from 'path';
import Link from 'next/link';
import { ArrowLeft, FileCheck, Scale, AlertTriangle, Shield, UserCheck, Gavel, Mail, Printer, Download } from 'lucide-react';

export default function MemorialAuthorizationPage() {
    const filePath = path.join(process.cwd(), 'content/legal/memorial-authorization.md');
    const content = fs.readFileSync(filePath, 'utf8');

    // Parse sections for TOC
    const sections = content.split('## ').slice(1).map(section => {
        const lines = section.split('\\n');
        const title = lines[0].trim();
        return {
            id: title.toLowerCase().replace(/[^a-z0-9]+/g, '-').substring(0, 50),
            title: title.replace(/\\*\\*/g, '').replace(/\\d+\\.\\d+\\s*/, '').trim()
        };
    });

    return (
        <div className="min-h-screen bg-ivory">
            {/* Header */}
            <div className="border-b border-sand/30 bg-white/80 backdrop-blur-sm sticky top-0 z-10">
                <div className="max-w-4xl mx-auto px-6 py-6">
                    <Link
                        href="/"
                        className="inline-flex items-center gap-2 text-charcoal/60 hover:text-charcoal transition-colors"
                    >
                        <ArrowLeft size={20} />
                        <span>Back to Home</span>
                    </Link>
                </div>
            </div>

            {/* Critical Warning Banner */}
            <div className="bg-terracotta/10 border-b-2 border-terracotta/30">
                <div className="max-w-4xl mx-auto px-6 py-6">
                    <div className="flex items-start gap-4">
                        <AlertTriangle className="text-terracotta shrink-0 mt-1" size={24} />
                        <div>
                            <h2 className="font-serif text-lg text-terracotta font-semibold mb-1">
                                Legally Binding Document
                            </h2>
                            <p className="text-charcoal/80 text-sm leading-relaxed">
                                This form creates a contractual agreement between you and Legacy Vault. It includes indemnification
                                clauses and representations of legal authority. If you do not understand these terms,
                                consult an attorney before signing.
                            </p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Hero Section */}
            <div className="bg-gradient-to-br from-charcoal via-charcoal/95 to-charcoal/90 text-ivory">
                <div className="max-w-4xl mx-auto px-6 py-16 text-center">
                    <div className="inline-flex items-center justify-center gap-2 px-4 py-2 bg-terracotta/20 text-terracotta rounded-full border border-terracotta/30 mb-6">
                        <FileCheck size={16} />
                        <span className="text-sm font-medium">Required for All Memorials</span>
                    </div>
                    <h1 className="font-serif text-5xl md:text-6xl text-ivory mb-4">
                        Memorial Authorization Form
                    </h1>
                    <p className="text-lg text-ivory/80 max-w-2xl mx-auto leading-relaxed">
                        Establish your legal authority to create a memorial and protect Legacy Vault
                        from claims by other family members or third parties.
                    </p>
                    <div className="mt-8 flex flex-wrap items-center justify-center gap-4 text-sm text-ivory/60">
                        <span className="flex items-center gap-2">
                            <Scale size={16} className="text-terracotta" />
                            Legally Binding
                        </span>
                        <span className="flex items-center gap-2">
                            <Shield size={16} className="text-terracotta" />
                            Indemnification Included
                        </span>
                        <span className="flex items-center gap-2">
                            <UserCheck size={16} className="text-terracotta" />
                            E-SIGN Act Compliant
                        </span>
                    </div>
                </div>
            </div>

            {/* Main Content */}
            <div className="max-w-4xl mx-auto px-6 py-12">
                <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
                    {/* Table of Contents */}
                    <div className="hidden lg:block lg:col-span-1">
                        <div className="sticky top-24 space-y-2">
                            <h3 className="font-serif text-lg text-charcoal mb-4">Form Sections</h3>
                            <nav className="space-y-1">
                                {sections.map((section, idx) => (
                                    <a
                                        key={idx}
                                        href={`#${section.id}`}
                                        className="block text-sm text-charcoal/60 hover:text-terracotta hover:pl-2 transition-all py-1 border-l-2 border-transparent hover:border-terracotta"
                                    >
                                        {section.title}
                                    </a>
                                ))}
                            </nav>

                            <div className="mt-8 space-y-4">
                                <div className="p-4 bg-gradient-to-br from-terracotta/5 to-sage/5 rounded-xl border border-sand/30">
                                    <h4 className="font-medium text-charcoal mb-2 flex items-center gap-2">
                                        <Mail size={16} className="text-terracotta" />
                                        Legal Questions?
                                    </h4>
                                    <p className="text-xs text-charcoal/60 mb-3">
                                        Contact our legal department for clarification.
                                    </p>
                                    <a
                                        href="mailto:legal@legacyvault.com"
                                        className="text-xs text-terracotta hover:text-terracotta/80 underline font-medium"
                                    >
                                        legal@legacyvault.com
                                    </a>
                                </div>

                                <div className="p-4 bg-sage/5 rounded-xl border border-sand/30">
                                    <h4 className="font-medium text-charcoal mb-2 flex items-center gap-2">
                                        <Download size={16} className="text-sage" />
                                        Download PDF
                                    </h4>
                                    <p className="text-xs text-charcoal/60 mb-3">
                                        Print and sign manually if preferred.
                                    </p>
                                    <button className="text-xs text-sage hover:text-sage/80 underline font-medium">
                                        Download Form (PDF)
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Content */}
                    <div className="lg:col-span-3">
                        {/* Quick Action Cards */}
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-12">
                            <div className="p-5 bg-white rounded-xl border-2 border-terracotta/20 shadow-sm">
                                <div className="flex items-center gap-3 mb-3">
                                    <div className="p-2 bg-terracotta/10 rounded-lg">
                                        <Gavel className="text-terracotta" size={20} />
                                    </div>
                                    <h3 className="font-serif text-base text-charcoal">Authority</h3>
                                </div>
                                <p className="text-xs text-charcoal/70">
                                    Prove you have legal right to create this memorial
                                </p>
                            </div>

                            <div className="p-5 bg-white rounded-xl border-2 border-sage/20 shadow-sm">
                                <div className="flex items-center gap-3 mb-3">
                                    <div className="p-2 bg-sage/10 rounded-lg">
                                        <Shield className="text-sage" size={20} />
                                    </div>
                                    <h3 className="font-serif text-base text-charcoal">Indemnify</h3>
                                </div>
                                <p className="text-xs text-charcoal/70">
                                    Protect Legacy Vault from family disputes
                                </p>
                            </div>

                            <div className="p-5 bg-white rounded-xl border-2 border-sand/30 shadow-sm">
                                <div className="flex items-center gap-3 mb-3">
                                    <div className="p-2 bg-charcoal/10 rounded-lg">
                                        <FileCheck className="text-charcoal" size={20} />
                                    </div>
                                    <h3 className="font-serif text-base text-charcoal">Verify</h3>
                                </div>
                                <p className="text-xs text-charcoal/70">
                                    Confirm accuracy and copyright compliance
                                </p>
                            </div>
                        </div>

                        <article className="prose prose-lg max-w-none">
                            <div className="space-y-8">
                                {content.split('## ').slice(1).map((section, idx) => {
                                    const lines = section.split('\\n');
                                    const title = lines[0].replace(/\\*\\*/g, '').trim();
                                    const id = title.toLowerCase().replace(/[^a-z0-9]+/g, '-').substring(0, 50);

                                    // Special styling for critical sections
                                    const isCriticalSection = title.includes('Indemnification') || title.includes('Signature') || title.includes('CRITICAL');

                                    return (
                                        <section
                                            key={idx}
                                            id={id}
                                            className={`scroll-mt-24 p-6 rounded-xl border ${isCriticalSection ? 'bg-terracotta/5 border-terracotta/20' : 'bg-white border-sand/30'}`}
                                        >
                                            <h2 className={`font-serif text-2xl md:text-3xl mb-4 flex items-start gap-3 ${isCriticalSection ? 'text-terracotta' : 'text-charcoal'}`}>
                                                <span className={isCriticalSection ? 'text-terracotta' : 'text-sage'}>§</span>
                                                {title.replace(/\\d+\\.\\d+\\s*/, '').replace(/\\d+\\.\\s*/, '')}
                                            </h2>
                                            <div className="text-charcoal/80 leading-relaxed space-y-4 text-base">
                                                {lines.slice(1).join('\\n').split('\\n\\n').map((paragraph, pidx) => {
                                                    // Handle subheadings
                                                    if (paragraph.startsWith('### ')) {
                                                        const subheading = paragraph.replace('### ', '').replace(/\\*\\*/g, '');
                                                        return (
                                                            <h3 key={pidx} className="font-serif text-xl text-charcoal mt-6 mb-3">
                                                                {subheading}
                                                            </h3>
                                                        );
                                                    }

                                                    // Handle checkboxes
                                                    if (paragraph.includes('- [ ]') || paragraph.includes('- [x]')) {
                                                        const items = paragraph.split('\\n').filter(line => line.trim().startsWith('- ['));
                                                        return (
                                                            <div key={pidx} className="space-y-2 my-4 bg-sand/10 p-4 rounded-lg">
                                                                {items.map((item, iidx) => {
                                                                    const isChecked = item.includes('[x]');
                                                                    const text = item.replace(/- \\[.*?\\] /, '');
                                                                    return (
                                                                        <div key={iidx} className="flex items-start gap-3">
                                                                            <div className={`w-5 h-5 rounded border-2 mt-0.5 flex items-center justify-center ${isChecked ? 'bg-sage border-sage' : 'border-charcoal/30'}`}>
                                                                                {isChecked && <span className="text-white text-xs">✓</span>}
                                                                            </div>
                                                                            <span className="text-charcoal/80 text-sm" dangerouslySetInnerHTML={{
                                                                                __html: text.replace(/\\*\\*(.+?)\\*\\*/g, '<strong class="text-charcoal">$1</strong>')
                                                                            }} />
                                                                        </div>
                                                                    );
                                                                })}
                                                            </div>
                                                        );
                                                    }

                                                    // Handle signature blocks
                                                    if (paragraph.includes('___') || paragraph.includes('Signature')) {
                                                        return (
                                                            <div key={pidx} className="my-6 space-y-3">
                                                                {paragraph.split('\\n').map((line, lidx) => {
                                                                    if (line.includes('___')) {
                                                                        return (
                                                                            <div key={lidx} className="border-b-2 border-charcoal/30 py-2 my-2">
                                                                                <span className="text-charcoal/40 text-sm">
                                                                                    {line.replace(/[_]+/, ' ')}
                                                                                </span>
                                                                            </div>
                                                                        );
                                                                    }
                                                                    return (
                                                                        <p key={lidx} className="text-sm font-medium text-charcoal">
                                                                            {line.replace(/\\*\\*/g, '')}
                                                                        </p>
                                                                    );
                                                                })}
                                                            </div>
                                                        );
                                                    }

                                                    // Handle bullet points
                                                    if (paragraph.trim().startsWith('-') || paragraph.trim().startsWith('*')) {
                                                        const items = paragraph.split('\\n').filter(line => line.trim().startsWith('-') || line.trim().startsWith('*'));
                                                        return (
                                                            <ul key={pidx} className="space-y-2 my-4">
                                                                {items.map((item, iidx) => (
                                                                    <li key={iidx} className="flex items-start gap-3 text-charcoal/80">
                                                                        <span className="text-terracotta mt-1.5">•</span>
                                                                        <span dangerouslySetInnerHTML={{
                                                                            __html: item.replace(/^[-\\*]\\s*/, '').replace(/\\*\\*(.+?)\\*\\*/g, '<strong class="text-charcoal">$1</strong>')
                                                                        }} />
                                                                    </li>
                                                                ))}
                                                            </ul>
                                                        );
                                                    }

                                                    // Regular paragraph
                                                    if (paragraph.trim()) {
                                                        return (
                                                            <p key={pidx} className="text-charcoal/80" dangerouslySetInnerHTML={{
                                                                __html: paragraph
                                                                    .replace(/\\*\\*(.+?)\\*\\*/g, '<strong class="text-charcoal">$1</strong>')
                                                                    .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href="$2" class="text-sage hover:underline">$1</a>')
                                                                    .replace(/^\\s*##?\\s*/, '')
                                                            }} />
                                                        );
                                                    }
                                                    return null;
                                                })}
                                            </div>
                                        </section>
                                    );
                                })}
                            </div>
                        </article>

                        {/* Submission CTA */}
                        <div className="mt-16 p-8 bg-gradient-to-br from-charcoal to-charcoal/90 text-ivory rounded-2xl">
                            <div className="text-center mb-8">
                                <FileCheck className="mx-auto mb-4 text-terracotta" size={48} />
                                <h3 className="font-serif text-3xl mb-3">Ready to Submit?</h3>
                                <p className="text-ivory/80 max-w-md mx-auto">
                                    Complete this form before creating your memorial. This protects both you and Legacy Vault.
                                </p>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <a
                                    href="mailto:authorization@legacyvault.com"
                                    className="flex flex-col items-center gap-3 p-6 bg-ivory/10 hover:bg-ivory/20 rounded-xl transition-all text-center"
                                >
                                    <Mail size={24} className="text-terracotta" />
                                    <div>
                                        <div className="font-medium">Email Form</div>
                                        <div className="text-xs text-ivory/60">authorization@legacyvault.com</div>
                                    </div>
                                </a>

                                <button className="flex flex-col items-center gap-3 p-6 bg-terracotta hover:bg-terracotta/90 rounded-xl transition-all text-center">
                                    <Download size={24} className="text-ivory" />
                                    <div>
                                        <div className="font-medium">Upload Online</div>
                                        <div className="text-xs text-ivory/80">Secure portal (coming soon)</div>
                                    </div>
                                </button>

                                <div className="flex flex-col items-center gap-3 p-6 bg-ivory/10 rounded-xl text-center">
                                    <Printer size={24} className="text-sage" />
                                    <div>
                                        <div className="font-medium">Mail Form</div>
                                        <div className="text-xs text-ivory/60">Wilmington, DE address</div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Cross-link */}
                        <div className="mt-8 text-center">
                            <p className="text-charcoal/60 text-sm">
                                This form is required by our{' '}
                                <Link href="/legal/terms" className="text-sage hover:underline">Terms of Service</Link>
                                {' '}and{' '}
                                <Link href="/legal/content-policy" className="text-sage hover:underline">Content Policy</Link>
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
